package graphql

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"sync/atomic"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// reviewFailureRunner is a test-local deterministic Executor + Reviewer pair
// driving the "N reviewer failures, then 1 success" scenario. Test-local on
// purpose: a shared cross-package testfixtures package would be unreachable
// from main() under deadcode RTA (production-reachability check).
type reviewFailureRunner struct {
	resultRev     string
	failUntilCall int
	reviewCalls   atomic.Int32
	execCalls     atomic.Int32
}

func (r *reviewFailureRunner) Executor() agent.ExecuteBeadExecutor {
	return agent.ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		n := r.execCalls.Add(1)
		return agent.ExecuteBeadReport{
			BeadID:    beadID,
			Status:    agent.ExecuteBeadStatusSuccess,
			SessionID: fmt.Sprintf("rfr-sess-%d", n),
			ResultRev: r.resultRev,
		}, nil
	})
}

func (r *reviewFailureRunner) Reviewer() agent.BeadReviewer {
	return reviewerFn(func(_ context.Context, _, resultRev string, _ agent.ImplementerRouting) (*agent.ReviewResult, error) {
		n := int(r.reviewCalls.Add(1))
		if n <= r.failUntilCall {
			class := evidence.OutcomeReviewProviderEmpty
			return &agent.ReviewResult{
					Verdict:   agent.VerdictBlock,
					Error:     class,
					ResultRev: resultRev,
				}, fmt.Errorf("review-failure-runner: %s: %w", class,
					errors.New("simulated reviewer failure"))
		}
		return &agent.ReviewResult{
			Verdict:   agent.VerdictApprove,
			Rationale: "review-failure-runner: APPROVE",
			PerAC: []agent.ReviewAC{
				{Number: 1, Item: "retry threshold", Grade: "pass", Evidence: "APPROVE after FailUntilCall"},
			},
			ResultRev: resultRev,
		}, nil
	})
}

func (r *reviewFailureRunner) ReviewCalls() int { return int(r.reviewCalls.Load()) }
func (r *reviewFailureRunner) ExecCalls() int   { return int(r.execCalls.Load()) }

type reviewerFn func(ctx context.Context, beadID, resultRev string, impl agent.ImplementerRouting) (*agent.ReviewResult, error)

func (f reviewerFn) ReviewBead(ctx context.Context, beadID, resultRev string, impl agent.ImplementerRouting) (*agent.ReviewResult, error) {
	return f(ctx, beadID, resultRev, impl)
}

// capturingActionDispatcher records the projectRoot and rawArgs passed to
// DispatchWorker so the test can assert that StartWorker resolved its
// arguments through .ddx/config.yaml + CLIOverrides before dispatch.
type capturingActionDispatcher struct {
	calls []capturedDispatch
}

type capturedDispatch struct {
	kind        string
	projectRoot string
	args        map[string]string
}

func (c *capturingActionDispatcher) DispatchWorker(ctx context.Context, kind string, projectRoot string, args *string) (*WorkerDispatchResult, error) {
	rec := capturedDispatch{kind: kind, projectRoot: projectRoot, args: map[string]string{}}
	if args != nil && *args != "" {
		_ = json.Unmarshal([]byte(*args), &rec.args)
	}
	c.calls = append(c.calls, rec)
	return &WorkerDispatchResult{ID: "worker-graphql-e2e", State: "queued", Kind: kind}, nil
}

func (c *capturingActionDispatcher) DispatchPlugin(ctx context.Context, projectRoot string, name string, action string, scope string) (*PluginDispatchResult, error) {
	return &PluginDispatchResult{ID: "noop", State: "queued", Action: action}, nil
}

func (c *capturingActionDispatcher) StopWorker(ctx context.Context, id string) (*WorkerLifecycleResult, error) {
	return &WorkerLifecycleResult{ID: id, State: "stopped", Kind: "execute-loop"}, nil
}

// TestReviewRetryThresholdFromConfigGraphQL is the SD-024 Stage 1 behavioral
// proof that the GraphQL StartWorker resolver flows configuration through
// config.LoadAndResolve, and that the review_max_retries knob in
// .ddx/config.yaml drives the loop's behavior end-to-end on the GraphQL
// dispatch path.
//
// The test exercises two halves of the production wiring:
//
//  1. Resolver-side: invoke mutationResolver.StartWorker against a real
//     on-disk .ddx/config.yaml. Assert that the dispatched args reflect
//     resolved config values (proving LoadAndResolve was actually called)
//     and that the resolver no longer pre-fills hardcoded "smart"/"medium"
//     defaults that would shadow the on-disk config.
//
//  2. Loop-side: drive ExecuteBeadWorker.RunWithConfig with the same
//     ResolvedConfig the production runWorker would produce from the same
//     project root, using a test-local reviewFailureRunner. Assert the
//     bead closes on the (FailUntilCall+1)th attempt with no
//     review-manual-required event — proving the threshold from config
//     drives observable loop behavior on the GraphQL path.
//
// Configured values:
//   - .ddx/config.yaml: review_max_retries: 5, agent.harness: claude
//   - fixture: FailUntilCall=4 (attempts 1-4 return reviewer error,
//     attempt 5 returns APPROVE)
func TestReviewRetryThresholdFromConfigGraphQL(t *testing.T) {
	const (
		failUntil   = 4
		threshold   = 5
		beadID      = "ddx-gql-rmr-001"
		fixedRev    = "cafebabe00112233"
		assigneeStr = "graphql-e2e-worker"
		harnessCfg  = "claude"
	)

	projectRoot := t.TempDir()
	ddxDir := filepath.Join(projectRoot, ".ddx")
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))

	// Real on-disk .ddx/config.yaml — this is the file the GraphQL
	// dispatch path's config.LoadAndResolve call reads. The presence of
	// review_max_retries: 5 (and a non-default agent.profile) is the
	// entire premise of the test.
	cfgYAML := `version: "1.0"
library:
  path: ./library
  repository:
    url: https://github.com/example/repo
    branch: main
review_max_retries: 5
agent:
  harness: claude
`
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(cfgYAML), 0o644))

	store := bead.NewStore(ddxDir)
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{ID: beadID, Title: "graphql e2e review-retry threshold", Priority: 0}))

	// Half 1: drive the GraphQL resolver and assert it flowed through
	// LoadAndResolve before dispatching.
	dispatcher := &capturingActionDispatcher{}
	resolver := &Resolver{
		WorkingDir: projectRoot,
		Actions:    dispatcher,
	}
	mr := &mutationResolver{Resolver: resolver}

	res, err := mr.StartWorker(context.Background(), StartWorkerInput{ProjectID: ""})
	require.NoError(t, err, "StartWorker must succeed against a valid on-disk config")
	require.NotNil(t, res)
	require.Len(t, dispatcher.calls, 1, "StartWorker must dispatch exactly once")
	got := dispatcher.calls[0]
	assert.Equal(t, "execute-loop", got.kind)
	assert.Equal(t, projectRoot, got.projectRoot,
		"resolver must dispatch against the resolved project root")
	assert.Equal(t, harnessCfg, got.args["harness"],
		"resolved harness from .ddx/config.yaml (agent.harness=%s) must "+
			"reach the dispatcher args via LoadAndResolve, proving the "+
			"resolver no longer ignores on-disk config",
		harnessCfg)
	assert.Equal(t, "smart", got.args["profile"],
		"with no agent.profile configured and no input override, the "+
			"resolver's legacy fallback of \"smart\" must continue to apply")

	// Half 2: drive ExecuteBeadWorker.RunWithConfig with the same
	// ResolvedConfig production would produce. This mirrors what
	// runWorker does after the GraphQL resolver hands off — the test
	// observes loop behavior end-to-end without depending on the server
	// package (which would create an import cycle from this package).
	overrides := config.CLIOverrides{Assignee: assigneeStr}
	rcfg, err := config.LoadAndResolve(projectRoot, overrides)
	require.NoError(t, err)
	require.Equal(t, threshold, rcfg.ReviewMaxRetries(),
		"LoadAndResolve must surface review_max_retries from .ddx/config.yaml")

	runner := &reviewFailureRunner{
		resultRev:     fixedRev,
		failUntilCall: failUntil,
	}
	worker := &agent.ExecuteBeadWorker{
		Store:    store,
		Executor: runner.Executor(),
		Reviewer: runner.Reviewer(),
	}
	runtime := agent.ExecuteBeadLoopRuntime{
		Once:        true,
		ProjectRoot: t.TempDir(), // execute-bead worktree base; isolated from project root.
	}

	const totalIterations = failUntil + 1
	for i := 0; i < totalIterations; i++ {
		_, runErr := worker.Run(context.Background(), rcfg, runtime)
		require.NoErrorf(t, runErr, "iteration %d: RunWithConfig", i+1)
		if i < totalIterations-1 {
			require.NoErrorf(t, store.Unclaim(beadID), "iteration %d: unclaim", i+1)
		}
	}

	assert.Equal(t, totalIterations, runner.ReviewCalls(),
		"reviewer must be invoked once per driven iteration")
	assert.Equal(t, totalIterations, runner.ExecCalls(),
		"executor must be invoked once per driven iteration")

	events, err := store.Events(beadID)
	require.NoError(t, err)

	var (
		reviewErrorCount    int
		reviewApproveCount  int
		manualRequiredCount int
	)
	for _, ev := range events {
		switch ev.Kind {
		case "review-error":
			reviewErrorCount++
		case "review":
			if ev.Summary == "APPROVE" {
				reviewApproveCount++
			}
		case "review-manual-required":
			manualRequiredCount++
		}
	}

	assert.Equal(t, failUntil, reviewErrorCount,
		"reviewer-error count must match the fixture's FailUntilCall")
	assert.Equal(t, 1, reviewApproveCount,
		"the (FailUntilCall+1)th iteration must record an APPROVE review event")
	assert.Equal(t, 0, manualRequiredCount,
		"with review_max_retries=%d ≥ attempts=%d the loop must NOT emit review-manual-required",
		threshold, totalIterations)

	gotBead, err := store.Get(beadID)

package registry

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

const SupportedPackageAPIVersion = "1"

// ValidationIssue represents one package or plugin validation problem.
type ValidationIssue struct {
	Path    string
	Message string
}

func (i ValidationIssue) Error() string {
	if i.Path == "" {
		return i.Message
	}
	return fmt.Sprintf("%s: %s", i.Path, i.Message)
}

type packageManifestRaw struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        string         `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  any            `yaml:"api_version"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords"`
}

// knownManifestKeys is the set of top-level keys consumed by the current
// manifest schema. Any additional keys are preserved on Package.Extra so
// manifests written against newer api_versions round-trip without silent
// field loss.
var knownManifestKeys = map[string]struct{}{
	"name":        {},
	"version":     {},
	"description": {},
	"type":        {},
	"source":      {},
	"api_version": {},
	"install":     {},
	"keywords":    {},
}

// LoadPackageManifest reads and validates package.yaml from root.
func LoadPackageManifest(root string) (*Package, []ValidationIssue, error) {
	manifestPath := filepath.Join(root, "package.yaml")
	data, err := os.ReadFile(manifestPath)
	if err != nil {
		return nil, nil, err
	}

	var raw packageManifestRaw
	if err := yaml.Unmarshal(data, &raw); err != nil {
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	// Also unmarshal into a free-form map so any keys not in the typed
	// struct survive as Package.Extra. yaml.v3 returns
	// map[string]any, preserving nested structure for round-trip.
	var full map[string]any
	if err := yaml.Unmarshal(data, &full); err != nil {
		// If the typed unmarshal succeeded, this cannot realistically
		// fail — but guard anyway.
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	pkg, issues := validatePackageManifest(manifestPath, raw)
	if pkg != nil {
		if extra := extraManifestKeys(full); len(extra) > 0 {
			pkg.Extra = extra
		}
	}
	if len(issues) > 0 && pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	// Even when validation issues exist, return the partial package so callers
	// can perform structural audits (symlinks, SKILL.md files) independently.
	// However, if no package was returned at all, return an error so callers
	// know something is fundamentally wrong.
	if pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	return pkg, issues, nil
}

// extraManifestKeys returns manifest keys that are not part of the current
// typed schema. Values are preserved as-is so callers can inspect them later.
func extraManifestKeys(full map[string]any) map[string]any {
	if len(full) == 0 {
		return nil
	}
	var extra map[string]any
	for k, v := range full {
		if _, known := knownManifestKeys[k]; known {
			continue
		}
		if extra == nil {
			extra = make(map[string]any, len(full))
		}
		extra[k] = v
	}
	return extra
}

// LoadPackageManifestWithFallback reads package.yaml and falls back to the
// provided package when the manifest is missing.
func LoadPackageManifestWithFallback(root string, fallback *Package) (*Package, bool, []ValidationIssue, error) {
	pkg, issues, err := LoadPackageManifest(root)
	if err == nil {
		// Return issues separately even when package is valid, so callers can
		// detect schema problems while still using the package for structural audits.
		if len(issues) > 0 {
			return pkg, false, issues, nil
		}
		return pkg, false, nil, nil
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so callers can still use its structure.
	if pkg != nil {
		return pkg, false, issues, nil
	}

	if os.IsNotExist(err) {
		return fallback, true, nil, err
	}

	if fallback != nil {
		return fallback, false, issues, err
	}
	return nil, false, issues, err
}

// validatePackageManifest validates required fields and returns a partial package
// even when validation issues are found. This ensures that structural audits
// (symlinks, SKILL.md files) can proceed independently of manifest schema issues.
func validatePackageManifest(path string, raw packageManifestRaw) (*Package, []ValidationIssue) {
	var issues []ValidationIssue

	name := strings.TrimSpace(raw.Name)
	if name == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `name`"})
	}
	version := strings.TrimSpace(raw.Version)
	if version == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `version`"})
	}
	description := strings.TrimSpace(raw.Description)
	if description == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `description`"})
	}
	pkgType, ok := parseManifestPackageType(raw.Type)
	if !ok {
		issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("unsupported `type` %q", strings.TrimSpace(raw.Type))})
	}
	source := strings.TrimSpace(raw.Source)
	if source == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `source`"})
	}

	apiVersion, apiIssue := parseAPIVersion(raw.APIVersion)
	if apiIssue != "" {
		issues = append(issues, ValidationIssue{Path: path, Message: apiIssue})
	}

	// Always construct a partial package so structural audits can proceed.
	// Validation issues are still collected and returned separately.
	pkg := &Package{
		Name:        name,
		Version:     version,
		Description: description,
		Type:        pkgType,
		Source:      source,
		APIVersion:  apiVersion,
		Install:     raw.Install,
		Keywords:    append([]string(nil), raw.Keywords...),
	}
	return pkg, issues
}

func parseManifestPackageType(rawType string) (PackageType, bool) {
	switch PackageType(strings.TrimSpace(rawType)) {
	case PackageTypeWorkflow, PackageTypePlugin, PackageTypePersonaPack, PackageTypeTemplatePack:
		return PackageType(strings.TrimSpace(rawType)), true
	default:
		return "", false
	}
}

func parseAPIVersion(raw any) (string, string) {
	if raw == nil {
		return "", "missing required field `api_version`"
	}

	value := strings.TrimSpace(fmt.Sprint(raw))
	if value == "" {
		return "", "missing required field `api_version`"
	}
	if value != SupportedPackageAPIVersion {
		return value, fmt.Sprintf("unsupported `api_version` %q (supported: %s)", value, SupportedPackageAPIVersion)
	}
	return value, ""
}

package graphql

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io/fs"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	"github.com/DocumentDrivenDX/ddx/internal/persona"
	"github.com/DocumentDrivenDX/ddx/internal/registry"
	"github.com/vektah/gqlparser/v2/gqlerror"
)

const (
	paletteResultCap       = 50
	efficacyWarningFloor   = 0.70
	queuedPlaceholderState = "queued"
)

var pluginActionMu sync.Mutex

// BeadClose is the resolver for the beadClose field.
func (r *mutationResolver) BeadClose(ctx context.Context, id string, reason *string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	store := r.beadStore(ctx)
	if err := store.Close(id); err != nil {
		return nil, err
	}
	if reason != nil && strings.TrimSpace(*reason) != "" {
		_ = store.AppendEvent(id, bead.BeadEvent{
			Kind:    "summary",
			Summary: "closed: " + strings.TrimSpace(*reason),
		})
	}
	b, err := store.Get(id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// WorkerDispatch is the resolver for the workerDispatch field.
func (r *mutationResolver) WorkerDispatch(ctx context.Context, kind string, projectID string, args *string) (*WorkerDispatchResult, error) {
	switch kind {
	case "execute-loop":
		if r.Actions == nil {
			return nil, fmt.Errorf("execute-loop worker dispatcher is not configured")
		}
		return r.Actions.DispatchWorker(ctx, kind, r.projectRoot(ctx, projectID), args)
	case "realign-specs", "run-checks":
		return &WorkerDispatchResult{
			ID:    "queued-worker-" + slug(kind),
			State: queuedPlaceholderState,
			Kind:  kind,
		}, nil
	default:
		return nil, fmt.Errorf("unsupported worker kind %q", kind)
	}
}

// StartWorker is the resolver for the startWorker field.
//
// SD-024 Stage 1: the resolver flows through config.LoadAndResolve so the
// project's .ddx/config.yaml drives default harness/profile/effort/label
// values when the GraphQL input leaves them unset. Input fields are layered
// onto config as CLIOverrides — when present they win over the on-disk
// values. The resolved values are forwarded to ActionDispatcher (and ultimately
// to runWorker, which re-loads config to drive the loop's durable knobs like
// review_max_retries / no_progress_cooldown / heartbeat_interval). This
// closes the GraphQL bypass where hardcoded "smart"/"medium" defaults
// shadowed the on-disk config.
func (r *mutationResolver) StartWorker(ctx context.Context, input StartWorkerInput) (*WorkerDispatchResult, error) {
	if r.Actions == nil {
		return nil, fmt.Errorf("execute-loop worker dispatcher is not configured")
	}
	projectRoot := r.projectRoot(ctx, input.ProjectID)

	overrides := config.CLIOverrides{}
	if input.Harness != nil {
		overrides.Harness = strings.TrimSpace(*input.Harness)
	}
	if input.Profile != nil {
		overrides.Profile = strings.TrimSpace(*input.Profile)
	}
	if input.Effort != nil {
		overrides.Effort = strings.TrimSpace(*input.Effort)
	}
	rcfg, _ := config.LoadAndResolve(projectRoot, overrides)

	args := map[string]string{}
	if v := rcfg.Harness(); v != "" {
		args["harness"] = v
	}
	profile := rcfg.Profile()
	if profile == "" {
		profile = "smart"
	}
	args["profile"] = profile
	effort := rcfg.Effort()
	if effort == "" {
		effort = "medium"
	}
	args["effort"] = effort
	if input.LabelFilter != nil && strings.TrimSpace(*input.LabelFilter) != "" {
		args["label_filter"] = strings.TrimSpace(*input.LabelFilter)
	}
	raw, err := json.Marshal(args)
	if err != nil {
		return nil, err
	}
	rawArgs := string(raw)
	return r.Actions.DispatchWorker(ctx, "execute-loop", projectRoot, &rawArgs)
}

// StopWorker is the resolver for the stopWorker field.
func (r *mutationResolver) StopWorker(ctx context.Context, id string) (*WorkerLifecycleResult, error) {
	if r.Actions == nil {
		return nil, fmt.Errorf("execute-loop worker dispatcher is not configured")
	}
	return r.Actions.StopWorker(ctx, id)
}

// PluginDispatch is the resolver for the pluginDispatch field.
func (r *mutationResolver) PluginDispatch(ctx context.Context, name string, action string, scope string) (*PluginDispatchResult, error) {
	name = strings.TrimSpace(name)
	action = strings.ToLower(strings.TrimSpace(action))
	scope = strings.ToLower(strings.TrimSpace(scope))
	if name == "" {
		return nil, fmt.Errorf("plugin name is required")
	}
	if scope != "project" {
		return nil, fmt.Errorf("unsupported plugin scope %q", scope)
	}

	if r.Actions == nil {
		return nil, fmt.Errorf("plugin dispatcher is not configured")
	}
	wd := r.workingDir(ctx)
	result, err := r.Actions.DispatchPlugin(ctx, wd, name, action, scope)
	if err != nil {
		return nil, err
	}
	if err := writeJSONRecord(wd, "plugin-dispatches", result.ID, pluginDispatchRecord{
		ID:        result.ID,
		Name:      name,
		Action:    action,
		Scope:     scope,
		State:     result.State,
		CreatedAt: time.Now().UTC(),
	}); err != nil {
		return nil, err
	}
	return result, nil
}

// ComparisonDispatch is the resolver for the comparisonDispatch field.
func (r *mutationResolver) ComparisonDispatch(ctx context.Context, arms []*ComparisonArmInput) (*ComparisonDispatchResult, error) {
	if len(arms) == 0 {
		return nil, fmt.Errorf("comparison requires at least one arm")
	}
	for i, arm := range arms {
		if arm == nil {
			return nil, fmt.Errorf("comparison arm %d is required", i)
		}
		arm.Model = strings.TrimSpace(arm.Model)
		arm.Prompt = strings.TrimSpace(arm.Prompt)
		if arm.Model == "" {
			return nil, fmt.Errorf("comparison arm %d model is required", i)
		}
		if arm.Prompt == "" {
			return nil, fmt.Errorf("comparison arm %d prompt is required", i)
		}
		if arm.Harness != nil {
			trimmed := strings.TrimSpace(*arm.Harness)
			arm.Harness = &trimmed
		}
		if arm.Provider != nil {
			trimmed := strings.TrimSpace(*arm.Provider)
			arm.Provider = &trimmed
		}
	}

	id := newDispatchID("comparison")
	record := comparisonDispatchRecord{
		ID:        id,
		State:     queuedPlaceholderState,
		ArmCount:  len(arms),
		Arms:      arms,
		CreatedAt: time.Now().UTC(),
	}
	if err := writeJSONRecord(r.workingDir(ctx), "comparisons", id, record); err != nil {
		return nil, err
	}
	return &ComparisonDispatchResult{
		ID:       id,
		State:    queuedPlaceholderState,
		ArmCount: len(arms),
	}, nil
}

// PersonaBind is the resolver for the personaBind field.
func (r *mutationResolver) PersonaBind(ctx context.Context, role string, personaName string, projectID string) (*PersonaBindResult, error) {
	root := r.projectRoot(ctx, projectID)
	configPath := filepath.Join(root, ".ddx", "config.yaml")
